options.onInit:
console.log("📡 Dados recebidos:", data);

const htmlgraphicsValue = htmlNode.getElementById('htmlgraphics-value');
if (!htmlgraphicsValue || !data.series?.length) return;

// Cria mapa de interfaces com valores
const interfaceMap = {};

data.series.forEach(serie => {
  const metricLabel = serie.fields.find(f => f.name === 'metric')?.values?.[0] || '';
  const interfaceLabel = serie.fields.find(f => f.name === 'interface')?.values?.[0] || 'N/A';
  const valueField = serie.fields.find(f => f.name === 'value');
  const lastValue = valueField?.values?.get(valueField.values.length - 1);

  if (!interfaceMap[interfaceLabel]) {
    interfaceMap[interfaceLabel] = {};
  }

  if (/rx/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Rx = lastValue;
  } else if (/tx/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Tx = lastValue;
  } else if (/temperature|temperatura/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Temperature = lastValue;
  }
});

// Gera HTML da tabela
let tableHTML = `
  <table style="width: 100%; border-collapse: collapse; color: white; text-align: center; font-size: 12px;">
    <thead>
      <tr style="background: #00000e;">
        <th style="padding: 3px 8px;">Interface</th>
        <th style="padding: 3px 8px;">Rx Power</th>
        <th style="padding: 3px 8px;">Tx Power</th>
        <th style="padding: 3px 8px;">Temperatura</th>
      </tr>
    </thead>
    <tbody>
`;

Object.entries(interfaceMap).forEach(([iface, values]) => {
  tableHTML += `
    <tr>
      <td style="padding: 3px 8px;">${iface}</td>
      <td style="padding: 3px 8px;">${values.Rx ?? 'N/A'} dBm</td>
      <td style="padding: 3px 8px;">${values.Tx ?? 'N/A'} dBm</td>
      <td style="padding: 3px 8px;">${values.Temperature ?? 'N/A'} °C</td>
    </tr>
  `;
});

tableHTML += `
    </tbody>
  </table>
`;

htmlgraphicsValue.innerHTML = tableHTML;

options.onRender:
// 🟢 CORREÇÕES: Ajuste de cores para TX e Temperatura conforme padrão técnico

function getRxColor(value) {
  if (value === undefined || isNaN(value)) return "#b0bec5";
  if (value <= -40) return "#ff1744"; // Sem luz
  if (value < -30) return "#ffca28";  // Fraco
  return "#00e676"; // OK
}

function getTxColor(value) {
  if (value === undefined || isNaN(value)) return "#b0bec5";
  if (value < -10 || value > 0.5) return "#d32f2f"; // Crítico
  if (value >= -10 && value <= -1) return "#00e676"; // OK
  return "#fbc02d"; // Fora do ideal
}

function getTempColor(value) {
  if (value === undefined || isNaN(value)) return "#b0bec5";
  if (value >= 70 || value <= 5) return "#d32f2f";   // Crítico
  if (value >= 60) return "#fbc02d";                 // Alerta
  return "#00e676";                                  // OK
}

const tbody = htmlNode.querySelector("tbody");
if (!tbody || !data.series?.length) return;

const series = data.series[0];
const itemField = series.fields.find(f => f.name === 'item');
const valueField = series.fields.find(f => f.name === 'Last *');
if (!itemField || !valueField) return;

const itemValues = itemField.values;
const valueValues = valueField.values;

const interfaceMap = {};

for (let i = 0; i < itemValues.length; i++) {
  const itemName = itemValues.get(i);
  const value = valueValues.get(i);

  if (/peer:|interface/i.test(itemName)) continue;

  const laneMatch = itemName.match(/(100GE\S+):.*lane(\d+)/i);
  const metricMatch = itemName.match(/(.*?)(?:\s*[-:]?\s*)?(rx|tx|temperature|temperatura)/i);
  if (!metricMatch) continue;

  const iface = metricMatch[1].trim();
  const metric = metricMatch[2].toLowerCase();

  if (laneMatch) {
    const laneBase = laneMatch[1].trim();
    const laneIndex = laneMatch[2];
    if (!interfaceMap[laneBase]) interfaceMap[laneBase] = { lanes: {}, main: {} };
    if (!interfaceMap[laneBase].lanes[laneIndex]) interfaceMap[laneBase].lanes[laneIndex] = {};
    if (metric.includes("rx")) interfaceMap[laneBase].lanes[laneIndex].Rx = value;
    if (metric.includes("tx")) interfaceMap[laneBase].lanes[laneIndex].Tx = value;
    continue;
  }

  if (!interfaceMap[iface]) interfaceMap[iface] = { lanes: {}, main: {} };
  if (metric.includes("rx")) interfaceMap[iface].main.Rx = value;
  if (metric.includes("tx")) interfaceMap[iface].main.Tx = value;
  if (metric.includes("temp")) interfaceMap[iface].main.Temperature = value;
}

let bodyHTML = "";

Object.entries(interfaceMap).forEach(([iface, { main, lanes }]) => {
  const laneKeys = Object.keys(lanes);
  let avgRx = null, avgTx = null;

  if (laneKeys.length > 0) {
    const sumRx = laneKeys.map(k => lanes[k].Rx).filter(v => v !== undefined && !isNaN(v));
    const sumTx = laneKeys.map(k => lanes[k].Tx).filter(v => v !== undefined && !isNaN(v));
    if (sumRx.length > 0) avgRx = (sumRx.reduce((a, b) => a + b, 0) / sumRx.length).toFixed(2);
    if (sumTx.length > 0) avgTx = (sumTx.reduce((a, b) => a + b, 0) / sumTx.length).toFixed(2);
  }

  const rxValue = main.Rx !== undefined ? main.Rx : avgRx;
  const txValue = main.Tx !== undefined ? main.Tx : avgTx;

  bodyHTML += `
    <tr data-iface="${iface}" style="cursor:pointer;" title="Clique para ver detalhes da interface ${iface}">
      <td title="Interface: ${iface}"><b>${iface}</b></td>
      <td style="color: ${getRxColor(rxValue)};" title="Potência de recepção (Rx)">
        ${rxValue !== null ? rxValue + ' dBm' : 'N/A'}
      </td>
      <td style="color: ${getTxColor(txValue)};" title="Potência de transmissão (Tx)">
        ${txValue !== null ? txValue + ' dBm' : 'N/A'}
      </td>
      <td style="color: ${getTempColor(main.Temperature)};" title="Temperatura do módulo óptico">
        ${main.Temperature !== undefined ? main.Temperature + ' °C' : 'N/A'}
      </td>
    </tr>
  `;

  laneKeys.forEach(lane => {
    const laneData = lanes[lane];
    bodyHTML += `
      <tr data-lane-of="${iface}" style="display: none;">
        <td style="padding-left: 28px;" title="Subinterface óptica">↳ Lane ${lane}</td>
        <td style="color: ${getRxColor(laneData.Rx)};" title="Rx da Lane ${lane}">
          ${laneData.Rx !== undefined ? laneData.Rx + ' dBm' : 'N/A'}
        </td>
        <td style="color: ${getTxColor(laneData.Tx)};" title="Tx da Lane ${lane}">
