options.onRender:
function getStatusClass(value, min, mean) {
  if (value === 1) return 'up';
  if (value === 2 && value === min && value === mean) return 'unknown';
  if (value === 2) return 'down';
  return 'unknown';
}

function getInterfaceTypeLabel(name) {
  if (name.includes('100GE')) return '100G';
  if (name.includes('25GE')) return '25G';
  if (name.includes('XGigabitEthernet')) return '10G';
  return 'SFP';
}

function getInterfaceTypeClass(name) {
  if (name.includes('100GE')) return 'ge100';
  if (name.includes('XGigabitEthernet')) return 'xge10';
  return 'sfp';
}

const container = htmlNode.querySelector('#switch-grid');
container.innerHTML = '';

const series = data.series[0];
if (!series) {
  container.innerHTML = '<div style="color:red">⚠️ Nenhum dado encontrado</div>';
  return;
}

const itemField = series.fields.find(f => f.name === 'item');
const valueField = series.fields.find(f => f.name.includes('Last'));
const minField = series.fields.find(f => f.name.includes('Min'));
const meanField = series.fields.find(f => f.name.includes('Mean'));
const aliasField = series.fields.find(f => f.name.toLowerCase().includes('alias'));

if (!itemField || !valueField || !minField || !meanField) {
  container.innerHTML = '<div style="color:red">⚠️ Campos esperados não encontrados (Last, Min, Mean)</div>';
  return;
}

const interfaces = [];

for (let i = 0; i < itemField.values.length; i++) {
  const rawName = itemField.values.get(i);
  const last = Number(valueField.values.get(i));
  const min = Number(minField.values.get(i));
  const mean = Number(meanField.values.get(i));
  const alias = aliasField?.values?.get(i) || '';

  const match = rawName.match(/(GigabitEthernet|25GE|100GE|XGigabitEthernet|Virtual-Ethernet)\S*/);
  if (match) {
    interfaces.push({
      name: match[0],
      raw: rawName,
      status: last,
      min: min,
      mean: mean,
      alias: alias
    });
  }
}

// Ordenação por tipo + ordem lógica (slot/subslot/porta)
interfaces.sort((a, b) => {
  const pattern = /(\D+)(\d+)\/(\d+)\/(\d+)/;

  const parse = (name) => {
    const match = name.match(pattern);
    if (!match) return [name, 0, 0, 0];
    const [_, type, slot, subslot, port] = match;
    return [type, parseInt(slot), parseInt(subslot), parseInt(port)];
  };

  const [typeA, slotA, subslotA, portA] = parse(a.name);
  const [typeB, slotB, subslotB, portB] = parse(b.name);

  if (typeA !== typeB) return typeA.localeCompare(typeB);
  if (slotA !== slotB) return slotA - slotB;
  if (subslotA !== subslotB) return subslotA - subslotB;
  return portA - portB;
});

interfaces.forEach((iface) => {
  const statusClass = getStatusClass(iface.status, iface.min, iface.mean);
  const typeClass = getInterfaceTypeClass(iface.name);
  const label = getInterfaceTypeLabel(iface.name);

  const wrapper = document.createElement('div');
  wrapper.className = 'port-wrapper';

  const port = document.createElement('div');
  port.className = `port-box ${statusClass} ${typeClass}`;

  const portNumber = iface.name.match(/\d+\/\d+\/\d+/)?.[0] || iface.name;
  port.innerText = portNumber.split('/').pop();

  const aliasText = iface.alias ? ` (${iface.alias})` : '';
  port.title = `Interface ${iface.raw}${aliasText} – ${label} – ${iface.status === 1 ? 'UP' : iface.status === 2 ? 'DOWN' : 'Desativado'}`;

  const labelDiv = document.createElement('div');
  labelDiv.innerText = label;

  wrapper.appendChild(port);
  wrapper.appendChild(labelDiv);
  container.appendChild(wrapper);
});

