const seriesRaw = context?.panel?.data?.series || [];
const timeField = seriesRaw[0]?.fields.find(f => f.type === 'time');
if (!timeField) return { series: [] };

// ——— helpers ———
const formatSignal = v => (typeof v === 'number' ? `${v.toFixed(2)} dBm` : 'N/A');

const adjustColor = (hex, factor = 1) => {
  const f = parseInt(hex.slice(1), 16);
  const r = Math.min(255, Math.round(((f >> 16) & 255) * factor));
  const g = Math.min(255, Math.round(((f >> 8) & 255) * factor));
  const b = Math.min(255, Math.round((f & 255) * factor));
  return `rgb(${r},${g},${b})`;
};

const baseColors100GE = {
  '100GEO/0/0': '#00FFC6',
  '100GEO/0/1': '#6AD1FF',
  '100GEO/0/2': '#9966FF',
  '100GEO/0/3': '#FFB800',
};
const defaultPalette = ['#FF4D4D', '#66CCFF', '#FFCC00', '#33CC33'];
let colorIndex = 0;

const getLineColor = (name) => {
  const lane = name.match(/Lane\s?(\d)/i)?.[1] ?? '';
  const iface = name.match(/100GEO\/[\d/]+/i)?.[0];
  if (iface && baseColors100GE[iface]) {
    const f = 1 - ((parseInt(lane) || 0) * 0.15);
    return adjustColor(baseColors100GE[iface], Math.max(0.4, f));
  }
  return defaultPalette[colorIndex++ % defaultPalette.length];
};

// ——— series (Tx) ———
const allSeries = seriesRaw.flatMap((serie) => {
  const time = serie.fields.find(f => f.type === 'time');
  if (!time) return [];

  return serie.fields
    .filter(f => f.type === 'number' && /(tx|transmit).*?(power|signal|optical)/i.test(f.name))
    .map(field => {
      const values = field.values;
      const last = values.at(-1);
      const hasSignal = values.some(v => typeof v === 'number' && !isNaN(v));
      if (!hasSignal) return null;

      const base = field.name.split(':')[0]?.trim() || field.name;
      const lane = field.name.match(/Lane\s?(\d)/i)?.[1];
      const laneLabel = lane ? ` - Lane ${lane}` : '';
      const label = formatSignal(last);

      return {
        name: `${base}${laneLabel} (Tx) | ${label}`,
        type: 'line',
        smooth: true,
        showSymbol: false,
        sampling: 'lttb',
        lineStyle: { width: 1.1, color: getLineColor(field.name) },
        emphasis: { focus: 'series' },
        data: values.map((v, i) => [time.values[i], v]),
      };
    })
    .filter(Boolean);
});

// ——— chart option ———
return {
  title: {
    text: 'Tx Power (dBm)',
    subtext: 'Todas as Interfaces Tx',
    left: 'center',
    top: 10,
    textStyle: { color: '#E8F0F2', fontSize: 15, fontWeight: 'bold' },
    subtextStyle: { color: '#AAAAAA', fontSize: 11 },
  },

  // força o crosshair ter rótulo legível no tema escuro
  axisPointer: {
    type: 'cross',
    label: {
      show: true,
      color: '#FFFFFF',
      backgroundColor: 'rgba(0,0,0,0.6)',
      borderColor: 'rgba(255,255,255,0.2)',
      borderWidth: 1,
    },
    lineStyle: { color: 'rgba(255,255,255,0.35)' },
    crossStyle: { color: 'rgba(255,255,255,0.35)' },
  },

  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'cross' },
    backgroundColor: 'rgba(0,0,0,0.9)',
    textStyle: { color: '#FFFFFF' },
    // evita que css do tema do Grafana escureça o texto
    extraCssText: 'color:#FFFFFF;border:1px solid rgba(255,255,255,0.2);',
    formatter: (params) => {
      if (!params?.length || !params[0].value) return '';
      const { seriesName, value, color } = params[0];
      const date = new Date(value[0]);
      const val = typeof value[1] === 'number' ? formatSignal(value[1]) : 'N/A';
      const alerta = value[1] < -10 ? ' <span style="color:#FF4D4D">⚠ Sinal Crítico</span>' : '';
      const hh = String(date.getHours()).padStart(2, '0');
      const mm = String(date.getMinutes()).padStart(2, '0');
      const ss = String(date.getSeconds()).padStart(2, '0');
      return `Horário: ${hh}:${mm}:${ss}<br/><span style="color:${color}">●</span> ${seriesName} <b>${val}</b>${alerta}`;
    },
