const ifaceMap = {
  HundredGigabitEthernet: '100GE',
  TwentyFiveGigE: '25GE',
  TenGigabitEthernet: '10GE',
  XGigabitEthernet: 'XGE',
  GigabitEthernet: 'GE',
  FastEthernet: 'FE',
  Ethernet: 'Eth',
  'Virtual-Ethernet': 'VE'
};

const abbreviateInterface = (name) =>
  Object.entries(ifaceMap).reduce((acc, [key, val]) => acc.replace(new RegExp(key, 'gi'), val), name);

const series = context?.panel?.data?.series || [];

const signals = series.flatMap(serie => {
  const timeField = serie.fields.find(f => f.type === 'time');
  if (!timeField) return [];

  return serie.fields
    .filter(f => f.type === 'number')
    .map(field => {
      const last = parseFloat(field.values.at(-1));
      if (isNaN(last)) return null;
      const type = /rx|receive|in/i.test(field.name) ? 'Rx' : 'Tx';
      return {
        name: abbreviateInterface(field.name),
        value: last,
        type
      };
    })
