const seriesRaw = context?.panel?.data?.series || [];
const timeField = seriesRaw[0]?.fields.find(f => f.type === 'time');
if (!timeField) return { series: [] };

// ——— helpers ———
const formatSignal = v => (typeof v === 'number' ? `${v.toFixed(2)} dBm` : 'N/A');

const adjustColor = (hex, factor = 1) => {
  const f = parseInt(hex.slice(1), 16);
  const r = Math.min(255, Math.round(((f >> 16) & 255) * factor));
  const g = Math.min(255, Math.round(((f >> 8) & 255) * factor));
  const b = Math.min(255, Math.round((f & 255) * factor));
  return `rgb(${r},${g},${b})`;
};

const baseColors100GE = {
  '100GEO/0/0': '#00FFC6',
  '100GEO/0/1': '#6AD1FF',
  '100GEO/0/2': '#9966FF',
  '100GEO/0/3': '#FFB800',
};
const defaultPalette = ['#FF4D4D', '#66CCFF', '#FFCC00', '#33CC33'];
let colorIndex = 0;

const getLineColor = (name) => {
  const lane = name.match(/Lane\s?(\d)/i)?.[1] ?? '';
  const iface = name.match(/100GEO\/[\d/]+/i)?.[0];
  if (iface && baseColors100GE[iface]) {
    const f = 1 - ((parseInt(lane) || 0) * 0.15);
    return adjustColor(baseColors100GE[iface], Math.max(0.4, f));
  }
  return defaultPalette[colorIndex++ % defaultPalette.length];
};

// ——— series (Rx) ———
const allSeries = seriesRaw.flatMap((serie) => {
  const time = serie.fields.find(f => f.type === 'time');
  if (!time) return [];

  return serie.fields
    .filter(f => f.type === 'number' && /(rx|transmit).*?(power|signal|optical)/i.test(f.name))
    .map(field => {
      const values = field.values;
      const last = values.at(-1);
      const hasSignal = values.some(v => typeof v === 'number' && !isNaN(v));
      if (!hasSignal) return null;

      const base = field.name.split(':')[0]?.trim() || field.name;
      const lane = field.name.match(/Lane\s?(\d)/i)?.[1];
      const laneLabel = lane ? ` - Lane ${lane}` : '';
      const label = formatSignal(last);

      return {
        name: `${base}${laneLabel} (Tx) | ${label}`,
        type: 'line',
        smooth: true,
        showSymbol: false,
        sampling: 'lttb',
        lineStyle: { width: 1.1, color: getLineColor(field.name) },
        emphasis: { focus: 'series' },
        data: values.map((v, i) => [time.values[i], v]),
      };
    })
    .filter(Boolean);
});

// ——— chart option ———
return {
  title: {
    text: 'Rx Power (dBm)',
    subtext: 'Todas as Interfaces Rx',
    left: 'center',
