    textStyle: { color: '#FFFFFF' },
    // evita que css do tema do Grafana escureça o texto
    extraCssText: 'color:#FFFFFF;border:1px solid rgba(255,255,255,0.2);',
    formatter: (params) => {
      if (!params?.length || !params[0].value) return '';
      const { seriesName, value, color } = params[0];
      const date = new Date(value[0]);
      const val = typeof value[1] === 'number' ? formatSignal(value[1]) : 'N/A';
