const interfaceMap = {
  HundredGigabitEthernet: '100GE',
  TwentyFiveGigE: '25GE',
  TenGigabitEthernet: '10GE',
  XGigabitEthernet: 'XGE',
  GigabitEthernet: 'GE',
  FastEthernet: 'FE',
  'Virtual-Ethernet': 'VE',
  Ethernet: 'Eth'
};

const abbreviateInterface = name =>
  Object.entries(interfaceMap).reduce((acc, [key, abbr]) =>
    acc.replace(new RegExp(key, 'gi'), abbr), name);

const formatThroughput = val => (val / 1e9).toFixed(2); // Gb/s

const top5 = (context?.panel?.data?.series || []).flatMap(serie => {
  const time = serie.fields.find(f => f.type === 'time');
  if (!time) return [];

  return serie.fields
    .filter(f => f.type === 'number' && /Bits sent|Bits received/i.test(f.name))
    .map(field => {
      const val = field.values.at(-1);
      if (typeof val !== 'number' || isNaN(val)) return null;

      const dir = /sent/i.test(field.name) ? 'Sent' : 'Received';
      const match = field.name.match(/Interface ([^\(:]+)/i);
      const name = match ? match[1].trim() : field.name;

      return {
        yLabel: `${abbreviateInterface(name)} (${dir})`,
        fullName: field.name,
        value: val
      };
    })
    .filter(Boolean);
}).sort((a, b) => b.value - a.value).slice(0, 5);

return {
  title: {
    text: 'Top 5 Interfaces com Maior Tráfego',
    left: 'center',
    top: 10,
    textStyle: {
      color: '#ffffff',
      fontSize: 17,
      fontWeight: 700,
      textShadowColor: 'rgba(0,0,0,0.4)',
      textShadowBlur: 3
    }
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'shadow' },
    backgroundColor: 'rgba(0,0,0,0.85)',
    borderColor: '#00e5ff',
    borderWidth: 1,
    textStyle: { color: '#ffffff', fontSize: 15 },
    formatter: ({ 0: { dataIndex, value } }) => {
      const item = top5[dataIndex];
      return `<b>${item.fullName}</b><br/>Tráfego Máximo: <span style="color:#00e5ff;">${formatThroughput(value)} Gb/s</span>`;
    }
  },
  grid: {
    left: '4%',
    right: '8%',
    bottom: '5%',
    top: 65,
    containLabel: true
  },
  xAxis: {
    type: 'value',
    name: 'Tráfego',
    nameGap: 2,
    nameTextStyle: {
      color: '#aaf',
      fontWeight: 'bold',
      fontSize: 10
    },
    axisLabel: {
      color: '#aaa',
      formatter: v => `${formatThroughput(v)} Gb/s`
    },
    axisLine: { lineStyle: { color: 'rgba(255,255,255,0.15)' } },
    splitLine: {
      show: true,
      lineStyle: {
        color: 'rgba(255,255,255,0.05)',
        type: 'dashed'
      }
    }
  },
  yAxis: {
    type: 'category',
    inverse: true,
    data: top5.map(i => i.yLabel),
    axisLabel: {
      color: '#e0f7fa',
      fontWeight: 700,
      fontSize: 11,
      margin: 10
    },
    axisLine: { lineStyle: { color: 'rgba(255,255,255,0.1)' } }
  },
  series: [{
    type: 'bar',
    data: top5.map(i => i.value),
    itemStyle: {
      borderRadius: [1, 6, 6, 1],
      color: new context.echarts.graphic.LinearGradient(1, 0, 0, 0, [
        { offset: 0, color: '#00e5ff' },
        { offset: 1, color: '#56d5dc' }
      ])
    },
    label: {
      show: true,
      position: 'right',
      color: '#ffffff',
      fontWeight: 600,
      fontSize: 12,
      formatter: ({ data }) => `${formatThroughput(data)} Gb/s`,
